// Create a minimal valid spec for testing
const createMockSpec = (overrides?: Partial<AxisSpecV1['axes']>): AxisSpecV1 => ({
  kind: 'cartesian',
  units: 1,
  grid: { enabled: true },
  axes: {
    showNumbers: true,
    showLabels: true,
    ticks: 1,
    labels: { x: 'x', y: 'y' },
    origin: { x: 0, y: 0 },
    ...overrides,
  },
  viewport: { xMin: -10, xMax: 10, yMin: -10, yMax: 10 },
